+export default {
+    name: "DoctorCard",
+    data() {
+        return {
+            userId: "",
+            doctorData: {},
+        };
+    },
+    methods: {
+        // 生成完整的图片 URL
+        getFullImageUrl(imageName) {
+            return `http://localhost:9000/uploads/${imageName}`;
+        },
+        // 请求医生信息
+        requestDoctor() {
+            request
+                .get("admin/findDoctor", {
+                    params: {
+                        dId: this.userId,
+                    },
+                })
+                .then((res) => {
+                    if (res.data.status != 200)
+                        return this.$message.error("获取数据失败");
+                    this.doctorData = res.data.data;
+                });
