+        // token 解码
+        tokenDecode(token) {
+            if (token !== null) return jwtDecode(token);
+        },
+    },
+    created() {
+        // 解码 token 信息
+        this.userId = this.tokenDecode(getToken()).dId;
+        this.requestDoctor();
+        console.log(this.userId);
+    },
+};
+</script>
